import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

function HomePage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('http://localhost:8000/api/videos/')
      .then(response => {
        setVideos(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки видео:', error);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="fade-in" style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 20 }}>🎬</div>
          <p style={{ color: 'var(--text-secondary)' }}>Загрузка видео...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="fade-in">
      {/* Hero секция */}
      <div style={{
        textAlign: 'center',
        marginBottom: 48,
        padding: '60px 20px',
        background: 'linear-gradient(135deg, var(--bg-secondary) 0%, var(--bg-primary) 100%)',
        borderRadius: 24,
        border: '1px solid var(--border)'
      }}>
        <h1 style={{
          fontSize: 'clamp(32px, 5vw, 56px)',
          fontWeight: 700,
          marginBottom: 16,
          background: 'linear-gradient(135deg, #fff 0%, var(--accent) 100%)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent'
        }}>
          Видеоплатформа
        </h1>
        <p style={{ fontSize: 'clamp(16px, 2vw, 20px)', color: 'var(--text-secondary)' }}>
          Смотрите, загружайте и делитесь видео
        </p>
      </div>

      {/* Сетка видео */}
      {videos.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 60, backgroundColor: 'var(--bg-secondary)', borderRadius: 24 }}>
          <p style={{ fontSize: 18, color: 'var(--text-secondary)', marginBottom: 20 }}>📭 Пока нет видео</p>
          <Link to="/upload" style={{
            backgroundColor: 'var(--accent)',
            color: 'white',
            padding: '12px 24px',
            borderRadius: 24,
            textDecoration: 'none',
            fontWeight: 500,
            transition: 'var(--transition)'
          }}>
            Загрузить первое видео
          </Link>
        </div>
      ) : (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
          gap: 28
        }}>
          {videos.map(video => (
            <Link to={`/video/${video.id}`} key={video.id} style={{ textDecoration: 'none' }}>
              <div style={{
                backgroundColor: 'var(--bg-card)',
                borderRadius: 16,
                overflow: 'hidden',
                transition: 'transform 0.3s ease, box-shadow 0.3s ease',
                cursor: 'pointer',
                height: '100%'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-8px)';
                e.currentTarget.style.boxShadow = 'var(--shadow)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = 'none';
              }}>
                
                {/* Thumbnail */}
                <div style={{ position: 'relative', backgroundColor: '#000' }}>
                  {video.thumbnail ? (
                    <img 
                      src={`http://localhost:8000${video.thumbnail}`}
                      alt={video.title}
                      style={{ width: '100%', aspectRatio: '16/9', objectFit: 'cover' }}
                    />
                  ) : (
                    <div style={{
                      width: '100%',
                      aspectRatio: '16/9',
                      backgroundColor: 'var(--bg-hover)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: 48
                    }}>
                      🎬
                    </div>
                  )}
                </div>
                
                {/* Info */}
                <div style={{ padding: 16 }}>
                  <h3 style={{
                    color: 'var(--text-primary)',
                    fontSize: 16,
                    fontWeight: 600,
                    marginBottom: 8,
                    display: '-webkit-box',
                    WebkitLineClamp: 2,
                    WebkitBoxOrient: 'vertical',
                    overflow: 'hidden'
                  }}>
                    {video.title}
                  </h3>
                  <p style={{ color: 'var(--text-secondary)', fontSize: 14, marginBottom: 4 }}>
                    {video.uploaded_by_name || 'Аноним'}
                  </p>
                  <p style={{ color: 'var(--text-secondary)', fontSize: 12 }}>
                    {video.views || 0} просмотров
                  </p>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

export default HomePage;
